import { Dialog as DialogPrimitive } from '@base-ui/react/dialog';
import { clsx } from 'clsx';
import { createContext, useContext, type ComponentProps } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import { CloseButton } from '../close-button';
import styles from './Dialog.module.css';

type DialogModalMode = true | false | 'trap-focus';

const DEFAULT_CLOSE_BUTTON_LABEL = 'Close dialog';
const DialogModeContext = createContext<DialogModalMode>(true);

const createDialogHandle = DialogPrimitive.createHandle;

function Dialog<Payload = unknown>({
  modal = true,
  ...props
}: DialogPrimitive.Root.Props<Payload>) {
  return (
    <DialogModeContext.Provider value={modal}>
      <DialogPrimitive.Root modal={modal} {...props} />
    </DialogModeContext.Provider>
  );
}

function DialogTrigger({ className, render, ...props }: DialogPrimitive.Trigger.Props) {
  return (
    <DialogPrimitive.Trigger
      data-slot="dialog-trigger"
      render={render}
      className={mergeClassName(className, !render && styles.trigger)}
      {...props}
    />
  );
}

function DialogPortal(props: DialogPrimitive.Portal.Props) {
  return <DialogPrimitive.Portal data-slot="dialog-portal" {...props} />;
}

function DialogBackdrop({ className, ...props }: DialogPrimitive.Backdrop.Props) {
  return (
    <DialogPrimitive.Backdrop
      data-slot="dialog-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function DialogViewport({ className, ...props }: DialogPrimitive.Viewport.Props) {
  return (
    <DialogPrimitive.Viewport
      data-slot="dialog-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function DialogPopup({ className, ...props }: DialogPrimitive.Popup.Props) {
  return (
    <DialogPrimitive.Popup
      data-slot="dialog-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function DialogTitle({ className, ...props }: DialogPrimitive.Title.Props) {
  return (
    <DialogPrimitive.Title
      data-slot="dialog-title"
      className={mergeClassName(className, styles.title)}
      {...props}
    />
  );
}

function DialogDescription({ className, ...props }: DialogPrimitive.Description.Props) {
  return (
    <DialogPrimitive.Description
      data-slot="dialog-description"
      className={mergeClassName(className, styles.description)}
      {...props}
    />
  );
}

function DialogClose({ className, ...props }: DialogPrimitive.Close.Props) {
  return (
    <DialogPrimitive.Close
      data-slot="dialog-close"
      className={mergeClassName(className, styles.close)}
      {...props}
    />
  );
}

function DialogCloseIcon({
  className,
  children,
  'aria-label': ariaLabel = DEFAULT_CLOSE_BUTTON_LABEL,
  render,
  ...props
}: DialogPrimitive.Close.Props) {
  return (
    <DialogPrimitive.Close
      data-slot="dialog-close-icon"
      render={render ?? <CloseButton.Root aria-label={ariaLabel}>{children}</CloseButton.Root>}
      className={mergeClassName(className, styles.closeIcon)}
      {...props}
    />
  );
}

function DialogContent({ className, children, ...props }: DialogPrimitive.Popup.Props) {
  const isModal = useContext(DialogModeContext) === true;

  return (
    <DialogPortal>
      {isModal ? <DialogBackdrop /> : null}
      <DialogViewport className={isModal ? undefined : styles.viewportNonBlocking}>
        <DialogPopup className={className} {...props}>
          {children}
        </DialogPopup>
      </DialogViewport>
    </DialogPortal>
  );
}

function DialogHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="dialog-header" className={clsx(styles.header, className)} {...props} />;
}

function DialogFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="dialog-footer" className={clsx(styles.footer, className)} {...props} />;
}

function DialogBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="dialog-body" className={clsx(styles.body, className)} {...props} />;
}

export {
  Dialog,
  createDialogHandle,
  DialogTrigger,
  DialogPortal,
  DialogBackdrop,
  DialogViewport,
  DialogPopup,
  DialogTitle,
  DialogDescription,
  DialogClose,
  DialogCloseIcon,
  DialogContent,
  DialogHeader,
  DialogBody,
  DialogFooter,
};

@layer ui.components {
  .trigger,
  .close {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--dialog-control-height, var(--size-lg));
    margin: 0;
    padding: var(--dialog-control-padding-y, 0.5rem) var(--dialog-control-padding-x, 0.875rem);
    border: var(--dialog-control-border-width, var(--border-width-sm)) solid
      var(--dialog-control-border-color, var(--color-border));
    border-radius: var(--dialog-control-radius, var(--radius-md));
    background-color: var(--dialog-control-bg, var(--color-background));
    color: var(--dialog-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--dialog-control-font-size, var(--text-md));
    line-height: var(--dialog-control-line-height, var(--line-height-text-md));
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--dialog-control-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(
          --dialog-focus-ring-width,
          var(--dialog-control-border-width, var(--border-width-sm))
        )
        solid var(--dialog-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(--dialog-focus-ring-width, var(--dialog-control-border-width, var(--border-width-sm))) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--opacity-disabled);
    }
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--dialog-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--dialog-backdrop-blur, 4px)));
    transition:
      opacity var(--dialog-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--dialog-backdrop-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--dialog-backdrop-starting-opacity, 0);
      backdrop-filter: var(--dialog-backdrop-starting-blur, none);
    }

    &[data-ending-style] {
      opacity: var(--dialog-backdrop-ending-opacity, 0);
      backdrop-filter: var(--dialog-backdrop-ending-blur, none);
    }

    &[data-nested] {
      z-index: calc(var(--z-backdrop) + 1);
    }
  }

  .viewport {
    box-sizing: border-box;
    position: fixed;
    z-index: var(--z-modal);
    inset: 0;
    display: grid;
    place-items: center;
    overflow-y: auto;
    overscroll-behavior: contain;
    padding: var(--dialog-viewport-padding, var(--spacing-4));

    &[data-nested] {
      z-index: calc(var(--z-modal) + 1);
    }
  }

  .viewportNonBlocking {
    pointer-events: none;

    & > [data-slot='dialog-popup'] {
      pointer-events: auto;
    }
  }

  .popup {
    box-sizing: border-box;
    position: relative;
    width: min(
      var(--dialog-width, 28rem),
      var(--dialog-max-width, calc(100vw - var(--spacing-8, 2rem))),
      var(--available-width, calc(100vw - var(--spacing-8, 2rem)))
    );
    max-width: 100%;
    padding: var(--dialog-padding, var(--spacing-6));
    border: var(--dialog-border-width, var(--border-width-sm)) solid
      var(--dialog-border-color, var(--color-border));
    border-radius: var(--dialog-radius, var(--radius-lg));
    background-color: var(--dialog-bg, var(--color-popover));
    color: var(--dialog-color, var(--color-popover-foreground));
    box-shadow: var(--dialog-shadow, var(--shadow-lg));
    translate: 0 calc(var(--dialog-nested-offset-y, 1.25rem) * var(--nested-dialogs, 0));
    transform: scale(calc(1 - var(--dialog-nested-scale-step, 0.1) * var(--nested-dialogs, 0)));
    transition:
      opacity var(--dialog-transition, var(--transition-default)),
      transform var(--dialog-transition, var(--transition-default)),
      translate var(--dialog-transition, var(--transition-default));

    &[data-nested-dialog-open] {
      &::after {
        content: '';
        position: absolute;
        inset: 0;
        border-radius: inherit;
        background-color: var(--dialog-nested-overlay-bg, rgb(0 0 0 / 0.05));
      }
    }

    &[data-starting-style] {
      opacity: var(--dialog-popup-starting-opacity, 0);
      translate: var(--dialog-popup-starting-translate-x, 0)
        calc(
          var(--dialog-nested-offset-y, 1.25rem) * var(--nested-dialogs, 0) +
            var(--dialog-popup-starting-translate-y, 0)
        );
      transform: scale(
        calc(
          (1 - var(--dialog-nested-scale-step, 0.1) * var(--nested-dialogs, 0)) *
            var(--dialog-popup-starting-scale, var(--scale-popup))
        )
      );
    }

    &[data-ending-style] {
      opacity: var(--dialog-popup-ending-opacity, 0);
      translate: var(--dialog-popup-ending-translate-x, 0)
        calc(
          var(--dialog-nested-offset-y, 1.25rem) * var(--nested-dialogs, 0) +
            var(--dialog-popup-ending-translate-y, 0)
        );
      transform: scale(
        calc(
          (1 - var(--dialog-nested-scale-step, 0.1) * var(--nested-dialogs, 0)) *
            var(--dialog-popup-ending-scale, var(--scale-popup))
        )
      );
    }
  }

  .header {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    align-items: start;
    gap: var(--dialog-header-gap, var(--spacing-1));

    & > [data-slot='dialog-title'] {
      grid-column: 1;
    }

    & > [data-slot='dialog-close'],
    & > [data-slot='dialog-close-icon'] {
      grid-column: 2;
      justify-self: end;
    }

    & > [data-slot='dialog-description'] {
      grid-column: 1 / -1;
    }
  }

  .title {
    margin: 0;
    color: var(--dialog-title-color, var(--dialog-color, var(--color-popover-foreground)));
    font-size: var(--dialog-title-font-size, var(--text-lg));
    font-weight: var(--dialog-title-font-weight, var(--weight-semibold));
    line-height: var(--dialog-title-line-height, var(--line-height-text-lg));
  }

  .description,
  .body {
    color: var(
      --dialog-description-color,
      var(--dialog-muted-color, var(--color-muted-foreground))
    );
    font-size: var(--dialog-description-font-size, var(--text-md));
    line-height: var(--dialog-description-line-height, var(--line-height-text-md));
  }

  .description {
    margin: 0;
  }

  .footer {
    display: flex;
    justify-content: flex-end;
    gap: var(--dialog-footer-gap, var(--spacing-2));
    margin-top: var(--dialog-footer-margin-top, var(--spacing-6));
  }

  .closeIcon {
    --close-button-size: var(--dialog-close-icon-size, 1.75rem);
    --close-button-radius: var(--dialog-close-icon-radius, var(--radius-md));
    --close-button-color: var(
      --dialog-close-icon-color,
      var(--dialog-muted-color, var(--color-muted-foreground))
    );
    --close-button-color-hover: var(
      --dialog-close-icon-color-hover,
      var(--dialog-close-icon-color, var(--dialog-color, var(--color-popover-foreground)))
    );
    --close-button-bg: var(--dialog-close-icon-bg, transparent);
    --close-button-bg-hover: var(--dialog-close-icon-bg-hover, var(--color-accent));
    --close-button-focus-ring-color: var(
      --dialog-close-icon-focus-ring-color,
      var(--dialog-focus-ring-color, var(--color-ring))
    );
    --close-button-icon-size: var(--dialog-close-icon-glyph-size, 0.75rem);
    min-height: auto;
    padding: 0;
    border: 0;
  }

  .body {
    margin: var(--dialog-content-margin, var(--spacing-4) 0 0);
  }
}
